use crate::status::HelixState;

/// Root sentinel mask — cold watchful monitor
/// Tiny glyph changes per state, 15 FPS safe
pub fn root_frames(state: HelixState, tick: u64) -> Vec<&'static str> {
    match state {
        HelixState::Idle => match tick % 4 {
            0 => vec!["        ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C9} \u{25C9}\u{2551}", "  \u{2551}  \u{2500} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["        ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} - -\u{2551}", "  \u{2551}  \u{2500} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["        ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C9} \u{25C9}\u{2551}", "  \u{2551}  \u{2500} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Thinking => match tick % 4 {
            0 => vec!["  (\u{00B7}  ) ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{00AC} \u{00AC}\u{2551}", "  \u{2551}  ~ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            1 => vec!["  (\u{00B7}\u{00B7} ) ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{2310} \u{2310}\u{2551}", "  \u{2551}  ~ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["  (\u{00B7}\u{00B7}\u{00B7}) ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{00AC} \u{00AC}\u{2551}", "  \u{2551}  ~ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["  ( \u{00B7}\u{00B7}) ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{2310} \u{2310}\u{2551}", "  \u{2551}  ~ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Coding => match tick % 4 {
            0 => vec!["   [++] ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25A3} \u{25A3}\u{2551}", "  \u{2551}  \u{2550} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            1 => vec!["   [++] ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C8} \u{25C8}\u{2551}", "  \u{2551}  \u{2550} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["   [++] ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25A3} \u{25A3}\u{2551}", "  \u{2551}  _ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["   [++] ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C8} \u{25C8}\u{2551}", "  \u{2551}  \u{2550} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Reviewing => match tick % 4 {
            0 => vec!["  (src?)", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{00AC} \u{00AC}\u{2551}", "  \u{2551}  \u{2500} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            1 => vec!["  (src?)", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} - -\u{2551}", "  \u{2551}  \u{2500} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["  (diff)", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{00AC} \u{00AC}\u{2551}", "  \u{2551}  \u{2550} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["  (src?)", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} - -\u{2551}", "  \u{2551}  \u{2500} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Committing => match tick % 4 {
            0 => vec!["   <ok> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C9} \u{25C9}\u{2551}", "  \u{2551}  \u{25BF} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            1 => vec!["   <++> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C9} \u{25C9}\u{2551}", "  \u{2551}  \u{25BF} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["   <ok> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25CE} \u{25CE}\u{2551}", "  \u{2551}  \u{25BF} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["   <++> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C9} \u{25C9}\u{2551}", "  \u{2551}  \u{25BF} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Streaming => match tick % 4 {
            0 => vec!["  <~\u{00B7}> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C8} \u{25C8}\u{2551}", "  \u{2551} \u{2581}\u{2582}\u{2583}\u{2582}\u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            1 => vec!["  <~~> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25CE} \u{25CE}\u{2551}", "  \u{2551} \u{2582}\u{2583}\u{2582}\u{2581}\u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["  <\u{00B7}~> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C8} \u{25C8}\u{2551}", "  \u{2551} \u{2583}\u{2582}\u{2581}\u{2582}\u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["  <~~> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25CE} \u{25CE}\u{2551}", "  \u{2551} \u{2582}\u{2581}\u{2582}\u{2583}\u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Done => match tick % 4 {
            0 | 1 | 3 => vec!["   [ok] ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C9} \u{25C9}\u{2551}", "  \u{2551}  \u{25BF} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["   [ok] ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} - -\u{2551}", "  \u{2551}  \u{25BF} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Error => match tick % 4 {
            0 => vec!["   ( ! )", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} ! !\u{2551}", "  \u{2551}  _ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            1 => vec!["   (!!!)", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} ! !\u{2551}", "  \u{2551}  _ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["   ( ! )", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} x x\u{2551}", "  \u{2551}  _ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["   (!!!)", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} ! !\u{2551}", "  \u{2551}  _ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Deep => match tick % 4 {
            0 => vec!["  <:::> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25CE} \u{25CE}\u{2551}", "  \u{2551}  ~ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            1 => vec!["  <:::.>", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C9} \u{25C9}\u{2551}", "  \u{2551}  ~ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["  <.:::>", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25CE} \u{25CE}\u{2551}", "  \u{2551}  \u{2550} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["  <:::> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C9} \u{25C9}\u{2551}", "  \u{2551}  ~ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
        HelixState::Critical => match tick % 4 {
            0 => vec!["  <!!!> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C8} \u{25C8}\u{2551}", "  \u{2551}  \u{2550} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            1 => vec!["  <!!!> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} ! !\u{2551}", "  \u{2551}  \u{2550} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            2 => vec!["  <!!!> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} \u{25C8} \u{25C8}\u{2551}", "  \u{2551}  _ \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
            _ => vec!["  <!!!> ", "  \u{2554}\u{2550}\u{2550}\u{2550}\u{2550}\u{2557}", "  \u{2551} ! !\u{2551}", "  \u{2551}  \u{2550} \u{2551}", "  \u{255A}\u{2550}\u{2550}\u{2550}\u{2550}\u{255D}"],
        },
    }
}
